function scopeDemo() {
  // var is function-scoped
  if (true) {
    var x = 10;
    let y = 20;
    const z = 30;
  }

  console.log(x); // 10 (accessible! var ignores block)
  // console.log(y); // ReferenceError: y is not defined
  // console.log(z); // ReferenceError: z is not defined
}

scopeDemo();

// for loop quirk with var
for (var i = 0; i < 5; i++) {
  setTimeout(function() { console.log(i); }, 100);
}
// Logs: 5, 5, 5, 5, 5 (all see the same i)

for (let j = 0; j < 5; j++) {
  setTimeout(function() { console.log(j); }, 100);
}
// Logs: 0, 1, 2, 3, 4 (each iteration gets its own j)

console.log(a); // undefined (var hoisted + initialized)
var a = 5;

// console.log(b); // ReferenceError: Cannot access 'b' before initialization
let b = 10;

// console.log(c); // ReferenceError: Cannot access 'c' before initialization
const c = 15;

// The Temporal Dead Zone:
{
  // TDZ starts for 'd'
  // console.log(d); // ReferenceError!
  let d = 20;
  // TDZ ends for 'd'
  console.log(d); // 20
}

// var hoisting visualization:
// The above is interpreted as:
// var a;
// console.log(a); // undefined
// a = 5;

// let/const are hoisted but not initialized
// They exist in the scope but are in the TDZ

// var — can re-declare and re-assign
var name = 'Alice';
var name = 'Bob';     // OK: re-declared
name = 'Charlie';      // OK: re-assigned
console.log(name);     // 'Charlie'

// let — can re-assign but NOT re-declare
let age = 30;
// let age = 31;  // SyntaxError: Identifier 'age' has already been declared
age = 31;              // OK: re-assigned
console.log(age);      // 31

// const — cannot re-assign or re-declare
const birthYear = 1990;
// const birthYear = 1991;  // SyntaxError
// birthYear = 1992;       // TypeError: Assignment to constant variable
console.log(birthYear); // 1990

// const requires initialization
// const uninitialized;  // SyntaxError: Missing initializer

// But const objects CAN be mutated:
const user = { name: 'Alice' };
user.name = 'Bob';     // OK: mutation, not re-assignment
console.log(user.name); // 'Bob'
// user = { name: 'Charlie' };  // TypeError!

// ✅ const by default — never changes
const API_BASE = 'https://api.example.com';
const MAX_RETRIES = 3;
const config = {
  theme: 'dark',
  lang: 'en'
};

// ✅ let when re-assignment is needed
let currentUser = null;
let counter = 0;

function login(userData) {
  currentUser = userData;  // re-assignment
  counter++;               // re-assignment
}

// ❌ var — avoid in modern code
// var oldWay = 'deprecated'; // old style, avoid

// Common pitfalls:
// 1. for loops with var
for (var i = 0; i < 3; i++) {
  setTimeout(function() { console.log(i); }, 0);
}
// Logs: 3, 3, 3 (NOT 0, 1, 2)

// 2. Accidental global with var
function test() {
  var local = 1;
  leaked = 2;  // No var/let/const — creates global!
}
test();
console.log(leaked); // 2 (accidental global)

// 3. const does NOT freeze objects
const data = { items: [] };
data.items.push('new item');  // Allowed!
console.log(data.items); // ['new item']

function tdzDemo() {
  console.log('Start of function');

  // TDZ for 'value' starts here
  // 'value' exists in scope but is uninitialized

  function inner() {
    // 'value' is NOT accessible here either
    // TDZ continues until the let declaration
  }

  // console.log(value); // ReferenceError!
  // typeof value;      // ReferenceError! (not 'undefined'!)

  let value = 42;
  // TDZ ends here
  console.log(value);  // 42
}

tdzDemo();

